+func dashboardAgentType(pane tmux.Pane) (string, bool) {
+	agentType := agentTypeString(pane.Type)
+	if agentType == "user" {
+		return "", false
+	}
+	if agentType == "" {
+		agentType = "unknown"
+	}
+	return agentType, true
+}
